vector<int> nextGreaterElements(vector<int> &nums)
{
    int n = nums.size();
    vector<int> result(n, -1);

    for (int i = 0; i < n; i++)
    {
        for (int offset = 1; offset < n; offset++)
        {
            int j = (i + offset) % n;
            if (nums[j] > nums[i]) { result[i] = nums[j]; break; }
        }
    }

    return result;
}

