using namespace std;

vector<int> nextGreaterElements(vector<int> &nums)
{
    int n = nums.size();
    vector<int> result(n, -1);
    stack<int> indices;

    for (int i = 0; i < 2 * n; i++)
    {
        int actual = nums[i % n];

        while (!indices.empty() && nums[indices.top()] < actual)
        {
            result[indices.top()] = actual;
            indices.pop();
        }

        if (i < n) indices.push(i);
    }

    return result;
}

