using namespace std;

class StockSpanner {
public:
    vector<int> prices;

    int next(int price)
    {
        prices.push_back(price);
        int span = 0;

        for (int i = prices.size() - 1; i >= 0; i--)
        {
            if (prices[i] > price) break;
            span++;
        }

        return span;
    }
};

int main()
{
    StockSpanner spanner;
    vector<int> prices = {100, 80, 60, 70, 60, 75, 85};

    for (int p : prices) cout << spanner.next(p) << " ";

    return 0;
}

#include <iostream>
#include <vector>
#include <stack>

using namespace std;

class StockSpanner {
public:
    stack<pair<int,int>> st; // (price, span)

    int next(int price)
    {
        int span = 1;

        while (!st.empty() && st.top().first <= price)
        {
            span += st.top().second;
            st.pop();
        }

        st.push({price, span});
        return span;
    }
};

int main()
{
    StockSpanner spanner;
    vector<int> prices = {100, 80, 60, 70, 60, 75, 85};

    for (int p : prices) cout << spanner.next(p) << " ";

    return 0;
}

#include <iostream>
#include <vector>

using namespace std;

int largestRectangleArea(vector<int> &heights)
{
    int best = 0;

    for (int i = 0; i < heights.size(); i++)
    {
        int height = heights[i];
        int left = i, right = i;

        while (left > 0 && heights[left - 1] >= height) left--;
        while (right < heights.size() - 1 && heights[right + 1] >= height) right++;

        best = max(best, height * (right - left + 1));
    }

    return best;
}

int main()
{
    vector<int> heights = {2, 1, 5, 6, 2, 3};

    cout << largestRectangleArea(heights) << endl;

    return 0;
}

#include <iostream>
#include <vector>
#include <stack>

using namespace std;

int largestRectangleArea(vector<int> &heights)
{
    stack<int> indices;
    int best = 0;
    int n = heights.size();

    for (int i = 0; i <= n; i++)
    {
        int h = (i == n) ? 0 : heights[i]; // sentinel: force-flush the stack at the end

        while (!indices.empty() && heights[indices.top()] >= h)
        {
            int height = heights[indices.top()];
            indices.pop();

            int width = indices.empty() ? i : i - indices.top() - 1;
            best = max(best, height * width);
        }

        indices.push(i);
    }

    return best;
}

int main()
{
    vector<int> heights = {2, 1, 5, 6, 2, 3};

    cout << largestRectangleArea(heights) << endl;

    return 0;
}

