#include <vector>

using namespace std;

int trap(vector<int> &height)
{
    int n = height.size();
    int total = 0;

    for (int i = 0; i < n; i++)
    {
        int leftMax = 0, rightMax = 0;
        for (int j = 0; j <= i; j++) leftMax = max(leftMax, height[j]);
        for (int j = i; j < n; j++) rightMax = max(rightMax, height[j]);
        total += min(leftMax, rightMax) - height[i];
    }

    return total;
}

int main()
{
    vector<int> height = {0, 1, 0, 2, 1, 0, 1, 3, 2, 1, 2, 1};

    cout << trap(height) << endl;

    return 0;
}

#include <iostream>
#include <vector>
#include <stack>

using namespace std;

int trap(vector<int> &height)
{
    stack<int> indices;
    int total = 0;

    for (int i = 0; i < height.size(); i++)
    {
        while (!indices.empty() && height[indices.top()] < height[i])
        {
            int valley = indices.top();
            indices.pop();

            if (indices.empty()) break; // no left boundary — can't trap water

            int leftBoundary = indices.top();
            int boundedHeight = min(height[leftBoundary], height[i]) - height[valley];
            int width = i - leftBoundary - 1;

            total += boundedHeight * width;
        }
        indices.push(i);
    }

    return total;
}

int main()
{
    vector<int> height = {0, 1, 0, 2, 1, 0, 1, 3, 2, 1, 2, 1};

    cout << trap(height) << endl;

    return 0;
}

